(async()=>{try{
  var out={ver:(typeof APP_VERSION!=='undefined'?APP_VERSION:null)};
  // Simular op CERRADA con un movimiento cobrable seleccionado en el manifiesto
  var MOV={id:'MZ-OPS-1',tipo:'Libre',contacto:'C-LI1',nombreContacto:'Familia Torres',pax:3,monto:90,adicionales:''};
  var OP={id:'OP-CERR',bote:'Dona Paty',capacidad:20,ocupados:3,estado:'Cerrada',manifiesto:[MOV],manifiesto_pasados:[]};
  window.operacionesData=[OP];
  window.cajaData=[];
  window._gestionOpEstado='Cerrada';
  window.editandoMovId=MOV.id;
  // Verificar por inspeccion del HTML generado (path headless-seguro)
  var html=_itemManifiestoHTML(MOV);
  out.html_hasAdicionales=/abrirModalImpuestos/.test(html);
  out.html_hasCobrar=/abrirModalCaja\('cobro_directo'/.test(html);
  out.html_hasPasar=/abrirModalDerivar/.test(html);
  out.html_hasBorrar=/eliminarMovimiento/.test(html);
  out.soloLectura_cerrada=(window._gestionOpEstado==='Cerrada');
  // Ahora intentar renderizar el modal real de Gestion PAX
  var rendered=false;
  try{
    abrirModalGestionBote('OP-CERR');
    await new Promise(function(r){setTimeout(r,500);});
    window.editandoMovId=MOV.id;
    actualizarModalSiAbierto();
    await new Promise(function(r){setTimeout(r,300);});
    var lista=document.getElementById('gestion-manifiesto-lista');
    if(lista){
      lista._fp=null; // forzar re-render
      actualizarListaManifiestoSuave(OP.manifiesto);
      await new Promise(function(r){setTimeout(r,300);});
      var card=lista.querySelector('[data-mov-id="MZ-OPS-1"]');
      if(card){
        rendered=true;
        out.card_hasAdicionales=/Adicionales/.test(card.textContent)&&!!card.innerHTML.match(/abrirModalImpuestos/);
        out.card_hasCobrar=/Cobrar/.test(card.textContent);
        out.card_hasPasar=/Pasar/.test(card.textContent);
        out.card_hasBorrar=!!card.innerHTML.match(/eliminarMovimiento/);
        out.card_isSelected=/ring-orange/.test(card.className)||/ring-orange/.test(card.innerHTML);
        // formulario de venta oculto en op cerrada
        var box=document.getElementById('box-formulario-venta');
        out.formularioVentaOculto=box?box.classList.contains('hidden'):null;
      }
    }
  }catch(e2){out.renderErr=e2.message;}
  out.modalRendered=rendered;
  // Render visual honesto: montar la card EXACTA de _itemManifiestoHTML (op Cerrada, seleccionada) en un panel visible sobre el login para el screenshot.
  try{
    var panel=document.createElement('div');
    panel.style.cssText='position:fixed;inset:0;z-index:99999;background:#f3f4f6;padding:16px;overflow:auto;font-family:system-ui,sans-serif;';
    panel.innerHTML='<div style="max-width:360px;margin:0 auto;">'
      +'<div style="text-align:center;font-weight:900;color:#7B2030;font-size:13px;margin-bottom:4px;">GEST. PAX — OP CERRADA (stress-test)</div>'
      +'<div style="text-align:center;font-size:11px;color:#6b7280;margin-bottom:12px;">Dona Paty · <span style="background:#fee2e2;color:#b91c1c;padding:1px 8px;border-radius:8px;font-weight:800;">Cerrada</span></div>'
      +'<div style="background:#fff;border:1px solid #e5e7eb;border-radius:14px;padding:10px;">'+_itemManifiestoHTML(MOV)+'</div>'
      +'<div style="margin-top:12px;font-size:11px;color:#374151;background:#fff;border:1px solid #e5e7eb;border-radius:10px;padding:10px;">'
      +'✅ <b>Adicionales</b> visible &nbsp; ✅ <b>Cobrar</b> visible<br>🚫 <b>Pasar</b> oculto &nbsp; 🚫 <b>Borrar</b> oculto (gateados por soloLectura)</div>'
      +'</div>';
    document.body.appendChild(panel);
  }catch(_){}
  await new Promise(function(r){setTimeout(r,300);});
  out.overflowX=document.documentElement.scrollWidth>window.innerWidth;
  return out;
}catch(e){return{crash:e.message, stack:(e.stack||'').slice(0,300)}}})()
